import { useState } from 'react'
import DatePicker from '@/components/ui/DatePicker'

const Controlled = () => {
    const [date, setDate] = (useState < Date) | (null > new Date())
    const [dateRange, setDateRange] =
        useState <
        [Date | null, Date | null] >
        [new Date(2022, 11, 1), new Date(2022, 11, 5)]
    const [dateTime, setDateTime] = (useState < Date) | (null > new Date())

    const handleDatePickerChange = (date: Date | null) => {
        console.log('Selected date', date)
        setDate(date)
    }

    const handleRangePickerChange = (date: [Date | null, Date | null]) => {
        console.log('Selected range date', date)
        setDateRange(date)
    }

    const handleDateTimeChange = (val: Date | null) => {
        console.log('Selected date time: ', val)
        setDateTime(val)
    }

    return (
        <div className="flex flex-col gap-5">
            <DatePicker
                placeholder="Pick a date"
                value={date}
                onChange={handleDatePickerChange}
            />
            <DatePicker.DatePickerRange
                placeholder="Select dates range"
                value={dateRange}
                onChange={handleRangePickerChange}
            />
            <DatePicker.DateTimepicker
                placeholder="Pick date & time"
                value={dateTime}
                onChange={handleDateTimeChange}
            />
        </div>
    )
}

export default Controlled

CustomRender.code:
import DatePicker from '@/components/ui/DatePicker'
import Badge from '@/components/ui/Badge'

const CustomRender = () => {
    return (
        <DatePicker
            placeholder="Pick date"
            dayClassName={(date, { selected }) => {
                if (date.getDate() === 12 && !selected) {
                    return 'text-red-600'
                }

                if (selected) {
                    return 'text-white'
                }

                return 'text-gray-700 dark:text-gray-200'
            }}
            dayStyle={(date, { selected, outOfMonth }) => {
                if (date.getDate() === 18 && !selected) {
                    return { color: '#15c39a' }
                }

                if (outOfMonth) {
                    return {
                        opacity: 0,
                        pointerEvents: 'none',
                        cursor: 'default',
                    }
                }

                return {}
            }}
            renderDay={(date) => {
                const day = date.getDate()

                if (day !== 12) {
                    return <span>{day}</span>
                }

                return (
                    <span className="relative flex justify-center items-center w-full h-full">
                        {day}
                        <Badge
                            className="absolute bottom-1"
                            innerClass="h-1 w-1"
                        />
                    </span>
                )
            }}
        />
    )
}

export default CustomRender

